powershell -Command "
\$projectDir = 'C:\Users\Administrator\Desktop\리크 검사기 신진&엔케이\신진'
\$resxFiles = @('FrmMain.resx','FrmPart.resx','FrmSearch.resx','FrmSearch2.resx','FrmPassWord.resx','FrmTest.resx','FrmSet.resx','FrmSIgnal.resx','FrmSeq.resx')

foreach (\$f in \$resxFiles) {
    \$path = Join-Path \$projectDir \$f
    if (!(Test-Path \$path)) { Write-Host \"SKIP: \$f not found\"; continue }

    [xml]\$xml = Get-Content \$path -Encoding UTF8
    \$nodesToRemove = @()

    foreach (\$node in \$xml.root.ChildNodes) {
        if (\$node.NodeType -ne 'Element') { continue }
        if (\$node.Name -ne 'data' -and \$node.Name -ne 'metadata') { continue }

        \$nameAttr = \$node.GetAttribute('name')
        if ([string]::IsNullOrEmpty(\$nameAttr)) { continue }

