$projectDir = $PSScriptRoot
$resxFiles = @('FrmMain.resx','FrmPart.resx','FrmSearch.resx','FrmSearch2.resx','FrmPassWord.resx','FrmTest.resx','FrmSet.resx','FrmSIgnal.resx','FrmSeq.resx')

foreach ($f in $resxFiles) {
    $path = Join-Path $projectDir $f
    if (!(Test-Path $path)) { Write-Host "SKIP: $f not found"; continue }

    [xml]$xml = Get-Content $path -Encoding UTF8
    $removedCount = 0

    # Collect nodes to remove from <data> elements
    $dataNodes = @($xml.root.data)
    foreach ($node in $dataNodes) {
        if ($null -eq $node) { continue }
        $nameAttr = $node.name
        if ([string]::IsNullOrEmpty($nameAttr)) { continue }

        $shouldRemove = $false

        # NI/FlexCell/CWUIControls/ScatterGraph related
        if ($nameAttr -match 'AxCWUIControlsLib|CWUIControlsLib|NationalInstruments|FlexCell|ScatterGraph') {
            $shouldRemove = $true
        }
        # OcxState with axc prefix (CWUIControls buttons)
        elseif ($nameAttr -match '\.OcxState' -and $nameAttr -match '^axc') {
            $shouldRemove = $true
        }

        if ($shouldRemove) {
            $xml.root.RemoveChild($node) | Out-Null
            $removedCount++
        }
    }

    # Also check metadata nodes
    $metaNodes = @($xml.root.metadata)
    foreach ($node in $metaNodes) {
        if ($null -eq $node) { continue }
        $nameAttr = $node.name
        if ([string]::IsNullOrEmpty($nameAttr)) { continue }

        if ($nameAttr -match 'AxCWUIControlsLib|CWUIControlsLib|NationalInstruments|FlexCell|ScatterGraph|^axc') {
            $xml.root.RemoveChild($node) | Out-Null
            $removedCount++
        }
    }

    # Also check assembly nodes for NI references
    $asmNodes = @($xml.root.assembly)
    foreach ($node in $asmNodes) {
        if ($null -eq $node) { continue }
        $asmName = $node.name
        if ([string]::IsNullOrEmpty($asmName)) { continue }
        if ($asmName -match 'NationalInstruments|FlexCell|CWUIControlsLib') {
            $xml.root.RemoveChild($node) | Out-Null
            $removedCount++
        }
    }

    $settings = New-Object System.Xml.XmlWriterSettings
    $settings.Indent = $true
    $settings.IndentChars = '  '
    $settings.Encoding = New-Object System.Text.UTF8Encoding($true)

    $writer = [System.Xml.XmlWriter]::Create($path, $settings)
    $xml.Save($writer)
    $writer.Close()

    Write-Host "DONE: $f - removed $removedCount entries"
}

